#!/usr/bin/env node

const path = require('path');
const fs = require('fs');
const { calculateBodygraph } = require('./bodygraph');
const { generateBodygraphSvg } = require('./svg');

function parseDate(input) {
  // Support d.m.Y (e.g. 22.04.1993) → YYYY-MM-DD
  const dotMatch = input.match(/^(\d{1,2})\.(\d{1,2})\.(\d{4})$/);
  if (dotMatch) {
    const [, d, m, y] = dotMatch;
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }
  return input; // assume YYYY-MM-DD
}

function parseArgs() {
  const args = process.argv.slice(2);

  if (args.length < 5) {
    console.error(
      'Usage: node src/index.js <date> <time> <timezone> <lat> <lon> [svg-output-path]\n' +
      '\nExample:\n' +
      '  node src/index.js 15.07.1990 12:00 Europe/London 51.5074 -0.1278 ./chart.svg'
    );
    process.exit(1);
  }

  const date = parseDate(args[0]);
  const time = args[1];
  const tz = args[2];
  const lat = parseFloat(args[3]);
  const lon = parseFloat(args[4]);
  const svgPath = args[5] || null;

  if (!date || !time || !tz || isNaN(lat) || isNaN(lon)) {
    console.error('Error: invalid arguments. Check date, time, timezone, lat, lon.');
    process.exit(1);
  }

  return { date, time, tz, lat, lon, svgPath };
}

const { date, time, tz, lat, lon, svgPath } = parseArgs();
const ephemerisPath = path.resolve(__dirname, '..', 'ephemeris');

try {
  const result = calculateBodygraph(date, time, tz, lat, lon, ephemerisPath);
  console.log(JSON.stringify(result, null, 2));

  if (svgPath) {
    const svg = generateBodygraphSvg(result);
    const outputPath = path.resolve(process.cwd(), svgPath);
    fs.writeFileSync(outputPath, svg, 'utf-8');
    console.error(`SVG saved to: ${outputPath}`);
  }
} catch (err) {
  console.error('Error:', err.message);
  process.exit(1);
}
